    'c01-s4-li5': { en: 'A significant share of stockouts is caused by planning-system weaknesses rather than supply disruptions.', pt: 'Uma parte significativa das rupturas de stock é causada por deficiências do sistema de planeamento e não por perturbações no fornecimento.' },
    'c01-s4-li6': { en: 'The organization lacks one reliable view of demand, inventory, and availability.', pt: 'A organização carece de uma visão confiável de demanda, estoque e disponibilidade.' },
