    'c02-s2-li8': { en: 'Unclear ownership of constraints', pt: 'Propriedade pouco clara das restrições' },
    'c02-s2-li9': { en: 'Excessive schedule changes', pt: 'Mudanças excessivas de horário' },
    'c02-s2-p2': { en: 'The organization must address the immediate performance gap while protecting safety, quality, customer commitments, employee engagement, and financial discipline.', pt: 'A organização deve abordar a lacuna imediata de desempenho, protegendo ao mesmo tempo a segurança, a qualidade, os compromissos com os clientes, o envolvimento dos funcionários e a disciplina financeira.' },
