    'c02-s7-th4': { en: 'Forum', pt: 'Fórum' },
    'c02-s7-th5': { en: 'Cadence', pt: 'Cadência' },
    'c02-s7-th6': { en: 'Purpose', pt: 'Objetivo' },
    'c02-s8-li10': { en: 'Weekly verified financial impact', pt: 'Impacto financeiro verificado semanalmente' },
    'c02-s8-li6': { en: 'Loss rate below 8% in 90 days', pt: 'Taxa de perda abaixo de 8% em 90 dias' },
    'c02-s8-li7': { en: 'Schedule adherence above 90%', pt: 'Aderência ao cronograma acima de 90%' },
    'c02-s8-li8': { en: 'OEE improvement of 8–12 points', pt: 'Melhoria de OEE de 8–12 pontos' },
    'c02-s8-li9': { en: '30% reduction in unplanned downtime', pt: 'Redução de 30% no tempo de inatividade não planejado' },
    'c02-s8-p2': { en: 'KPIs should include clear definitions, owners, data sources, targets, thresholds, and required actions when performance moves outside tolerance.', pt: 'Os KPIs devem incluir definições claras, proprietários, fontes de dados, metas, limites e ações necessárias quando o desempenho ultrapassar a tolerância.' },
    'c02-s9-td-13': { en: 'Transformation fatigue', pt: 'Fadiga de transformação' },
    'c02-s9-td-14': { en: 'Limit priorities and visibly stop low-value work', pt: 'Limitar as prioridades e interromper visivelmente o trabalho de baixo valor' },
    'c02-s9-td-15': { en: 'Weak leadership alignment', pt: 'Fraco alinhamento de liderança' },
    'c02-s9-td-16': { en: 'Use explicit decision rights and sponsor routines', pt: 'Use direitos de decisão explícitos e rotinas de patrocinador' },
    'c02-s9-td-17': { en: 'Poor data quality', pt: 'Má qualidade de dados' },
    'c02-s9-td-18': { en: 'Establish baseline validation and metric governance', pt: 'Estabeleça validação de linha de base e governança de métricas' },
    'c02-s9-td-19': { en: 'Benefits not sustained', pt: 'Benefícios não sustentados' },
    'c02-s9-td-20': { en: 'Assign process owners and audit post-implementation results', pt: 'Atribuir proprietários de processos e auditar resultados pós-implementação' },
    'c02-s9-td-21': { en: 'Employee resistance', pt: 'Resistência dos funcionários' },
    'c02-s9-td-22': { en: 'Involve users in design and provide role-based support', pt: 'Envolva os usuários no design e forneça suporte baseado em funções' },
    'c02-s9-td-23': { en: 'Operational disruption', pt: 'Interrupção operacional' },
    'c02-s9-td-24': { en: 'Pilot changes and use readiness gates before scaling', pt: 'Mudanças piloto e uso de portões de prontidão antes de escalar' },
    'c02-s9-th3': { en: 'Risk', pt: 'Risco' },
    'c02-s9-th4': { en: 'Mitigation', pt: 'Mitigação' },
    'c03-s1-p3': { en: 'Senior leaders receive many reports but lack a coherent view of business performance. Indicators are inconsistent, backward-looking, and disconnected from strategic decisions.', pt: 'Os líderes seniores recebem muitos relatórios, mas carecem de uma visão coerente do desempenho empresarial. Os indicadores são inconsistentes, retrospectivos e desconectados das decisões estratégicas.' },
    'c03-s1-p4': { en: 'The recommended approach combines strategic prioritization, process redesign, governance, data discipline, leadership alignment, and change management. The objective is not only to improve short-term performance, but to create a management system capable of sustaining results.', pt: 'A abordagem recomendada combina priorização estratégica, redesenho de processos, governança, disciplina de dados, alinhamento de liderança e gestão de mudanças. O objetivo não é apenas melhorar o desempenho no curto prazo, mas criar um sistema de gestão capaz de sustentar resultados.' },
    'c03-s10-p2': { en: 'The transformation is expected to improve operational control, decision speed, accountability, workforce capability, customer outcomes, and financial performance. Final benefits would be validated jointly by operations and finance.', pt: 'Espera-se que a transformação melhore o controle operacional, a velocidade de decisão, a responsabilidade, a capacidade da força de trabalho, os resultados do cliente e o desempenho financeiro. Os benefícios finais seriam validados conjuntamente pelas operações e finanças.' },
    'c03-s11-p3': { en: 'Sustainable transformation is not a collection of isolated projects. It is a disciplined system that connects strategy, processes, people, governance, data, and value realization.', pt: 'A transformação sustentável não é um conjunto de projetos isolados. É um sistema disciplinado que conecta estratégia, processos, pessoas, governança, dados e realização de valor.' },
    'c03-s2-h3-2': { en: 'Current-State Signals', pt: 'Sinais do estado atual' },
    'c03-s2-li10': { en: 'No clear action thresholds', pt: 'Não há limites de ação claros' },
    'c03-s2-li6': { en: 'Too many KPIs', pt: 'Muitos KPIs' },
    'c03-s2-li7': { en: 'Conflicting definitions', pt: 'Definições conflitantes' },
    'c03-s2-li8': { en: 'Manual consolidation', pt: 'Consolidação manual' },
    'c03-s2-li9': { en: 'Predominantly lagging indicators', pt: 'Indicadores predominantemente atrasados' },
    'c03-s2-p2': { en: 'The organization must address the immediate performance gap while protecting safety, quality, customer commitments, employee engagement, and financial discipline.', pt: 'A organização deve abordar a lacuna imediata de desempenho, protegendo ao mesmo tempo a segurança, a qualidade, os compromissos com os clientes, o envolvimento dos funcionários e a disciplina financeira.' },
    'c03-s3-li10': { en: 'KPI and data-quality review', pt: 'Revisão de KPI e qualidade de dados' },
    'c03-s3-li11': { en: 'Root-cause analysis', pt: 'Análise de causa raiz' },
    'c03-s3-li12': { en: 'Capability and governance assessment', pt: 'Avaliação de capacidade e governança' },
    'c03-s3-li13': { en: 'Financial value-leakage analysis', pt: 'Análise de vazamento de valor financeiro' },
    'c03-s3-li14': { en: 'Risk and change-readiness evaluation', pt: 'Avaliação de riscos e prontidão para mudanças' },
    'c03-s3-li8': { en: 'Executive and frontline stakeholder interviews', pt: 'Entrevistas com executivos e partes interessadas da linha de frente' },
    'c03-s3-li9': { en: 'Process and value-stream mapping', pt: 'Mapeamento de processos e fluxo de valor' },
    'c03-s3-p2': { en: 'The assessment would combine:', pt: 'A avaliação combinaria:' },
    'c03-s4-li5': { en: 'A significant share of the performance gap is caused by management-system weaknesses rather than isolated technical issues.', pt: 'Uma parte significativa da lacuna de desempenho é causada por deficiências do sistema de gestão e não por questões técnicas isoladas.' },
    'c03-s4-li6': { en: 'The organization lacks one reliable view of priorities, performance, and ownership.', pt: 'A organização carece de uma visão confiável de prioridades, desempenho e propriedade.' },
    'c03-s4-li7': { en: 'Local improvements will not sustain without governance, capability building, and leadership routines.', pt: 'As melhorias locais não serão sustentadas sem governação, capacitação e rotinas de liderança.' },
    'c03-s4-li8': { en: 'The transformation should be sequenced to stabilize, improve, and then scale.', pt: 'A transformação deve ser sequenciada para estabilizar, melhorar e depois escalar.' },
    'c03-s5-li10': { en: 'Establish exception-based performance reviews', pt: 'Estabeleça avaliações de desempenho baseadas em exceções' },
    'c03-s5-li6': { en: 'Build a strategy-to-KPI architecture', pt: 'Construa uma arquitetura de estratégia para KPI' },
    'c03-s5-li7': { en: 'Define KPI owners and standard formulas', pt: 'Definir proprietários de KPI e fórmulas padrão' },
    'c03-s5-li8': { en: 'Balance leading and lagging indicators', pt: 'Equilibre indicadores avançados e atrasados' },
    'c03-s5-li9': { en: 'Create executive, tactical, and operational views', pt: 'Crie visões executivas, táticas e operacionais' },
