    'c03-s8-li6': { en: '100% KPI definition governance', pt: 'Governança de definição de KPI 100%' },
    'c03-s8-li7': { en: 'Reporting effort reduced by 50%', pt: 'Esforço de relatórios reduzido em 50%' },
