    'c03-s9-th4': { en: 'Mitigation', pt: 'Mitigação' },
    'c04-s1-p3': { en: 'A core operational process relies on spreadsheets, emails, and manual handoffs. Data is duplicated, approvals are slow, and customers receive inconsistent information.', pt: 'Um processo operacional central depende de planilhas, e-mails e transferências manuais. Os dados são duplicados, as aprovações são lentas e os clientes recebem informações inconsistentes.' },
    'c04-s1-p4': { en: 'The recommended approach combines strategic prioritization, process redesign, governance, data discipline, leadership alignment, and change management. The objective is not only to improve short-term performance, but to create a management system capable of sustaining results.', pt: 'A abordagem recomendada combina priorização estratégica, redesenho de processos, governança, disciplina de dados, alinhamento de liderança e gestão de mudanças. O objetivo não é apenas melhorar o desempenho no curto prazo, mas criar um sistema de gestão capaz de sustentar resultados.' },
    'c04-s10-p2': { en: 'The transformation is expected to improve operational control, decision speed, accountability, workforce capability, customer outcomes, and financial performance. Final benefits would be validated jointly by operations and finance.', pt: 'Espera-se que a transformação melhore o controle operacional, a velocidade de decisão, a responsabilidade, a capacidade da força de trabalho, os resultados do cliente e o desempenho financeiro. Os benefícios finais seriam validados conjuntamente pelas operações e finanças.' },
    'c04-s11-p3': { en: 'Sustainable transformation is not a collection of isolated projects. It is a disciplined system that connects strategy, processes, people, governance, data, and value realization.', pt: 'A transformação sustentável não é um conjunto de projetos isolados. É um sistema disciplinado que conecta estratégia, processos, pessoas, governança, dados e realização de valor.' },
    'c04-s2-h3-2': { en: 'Current-State Signals', pt: 'Sinais do estado atual' },
    'c04-s2-li10': { en: 'High approval latency', pt: 'Alta latência de aprovação' },
    'c04-s2-li6': { en: 'Disconnected systems', pt: 'Sistemas desconectados' },
    'c04-s2-li7': { en: 'Manual re-entry', pt: 'Reentrada manual' },
    'c04-s2-li8': { en: 'Low traceability', pt: 'Baixa rastreabilidade' },
    'c04-s2-li9': { en: 'Unclear process ownership', pt: 'Propriedade do processo pouco clara' },
    'c04-s2-p2': { en: 'The organization must address the immediate performance gap while protecting safety, quality, customer commitments, employee engagement, and financial discipline.', pt: 'A organização deve abordar a lacuna imediata de desempenho, protegendo ao mesmo tempo a segurança, a qualidade, os compromissos com os clientes, o envolvimento dos funcionários e a disciplina financeira.' },
