    'c05-s7-th6': { en: 'Purpose', pt: 'Objetivo' },
    'c05-s8-li10': { en: 'Sustained gap closure', pt: 'Fechamento sustentado de lacunas' },
    'c05-s8-li6': { en: 'Variation reduced by 30%', pt: 'Variação reduzida em 30%' },
    'c05-s8-li7': { en: 'Yield improvement across bottom-quartile sites', pt: 'Melhoria de rendimento em sites do quartil inferior' },
    'c05-s8-li8': { en: 'Shared standard adoption above 90%', pt: 'Adoção padrão compartilhada acima de 90%' },
    'c05-s8-li9': { en: 'Fewer quality deviations', pt: 'Menos desvios de qualidade' },
    'c05-s8-p2': { en: 'KPIs should include clear definitions, owners, data sources, targets, thresholds, and required actions when performance moves outside tolerance.', pt: 'Os KPIs devem incluir definições claras, proprietários, fontes de dados, metas, limites e ações necessárias quando o desempenho ultrapassar a tolerância.' },
    'c05-s9-td-13': { en: 'Transformation fatigue', pt: 'Fadiga de transformação' },
    'c05-s9-td-14': { en: 'Limit priorities and visibly stop low-value work', pt: 'Limitar as prioridades e interromper visivelmente o trabalho de baixo valor' },
    'c05-s9-td-15': { en: 'Weak leadership alignment', pt: 'Fraco alinhamento de liderança' },
