    'c05-s9-td-21': { en: 'Employee resistance', pt: 'Resistência dos funcionários' },
    'c05-s9-td-22': { en: 'Involve users in design and provide role-based support', pt: 'Envolva os usuários no design e forneça suporte baseado em funções' },
    'c05-s9-td-23': { en: 'Operational disruption', pt: 'Interrupção operacional' },
    'c05-s9-td-24': { en: 'Pilot changes and use readiness gates before scaling', pt: 'Mudanças piloto e uso de portões de prontidão antes de escalar' },
    'c05-s9-th3': { en: 'Risk', pt: 'Risco' },
    'c05-s9-th4': { en: 'Mitigation', pt: 'Mitigação' },
    'c06-s1-p3': { en: 'A transformation program is technically sound but progress is slow because teams feel overloaded, priorities change, and leaders manage through control rather than ownership.', pt: 'Um programa de transformação é tecnicamente sólido, mas o progresso é lento porque as equipas se sentem sobrecarregadas, as prioridades mudam e os líderes gerem através do controlo e não da propriedade.' },
    'c06-s1-p4': { en: 'The recommended approach combines strategic prioritization, process redesign, governance, data discipline, leadership alignment, and change management. The objective is not only to improve short-term performance, but to create a management system capable of sustaining results.', pt: 'A abordagem recomendada combina priorização estratégica, redesenho de processos, governança, disciplina de dados, alinhamento de liderança e gestão de mudanças. O objetivo não é apenas melhorar o desempenho no curto prazo, mas criar um sistema de gestão capaz de sustentar resultados.' },
    'c06-s10-p2': { en: 'The transformation is expected to improve operational control, decision speed, accountability, workforce capability, customer outcomes, and financial performance. Final benefits would be validated jointly by operations and finance.', pt: 'Espera-se que a transformação melhore o controle operacional, a velocidade de decisão, a responsabilidade, a capacidade da força de trabalho, os resultados do cliente e o desempenho financeiro. Os benefícios finais seriam validados conjuntamente pelas operações e finanças.' },
    'c06-s11-p3': { en: 'Sustainable transformation is not a collection of isolated projects. It is a disciplined system that connects strategy, processes, people, governance, data, and value realization.', pt: 'A transformação sustentável não é um conjunto de projetos isolados. É um sistema disciplinado que conecta estratégia, processos, pessoas, governança, dados e realização de valor.' },
    'c06-s2-h3-2': { en: 'Current-State Signals', pt: 'Sinais do estado atual' },
    'c06-s2-li10': { en: 'Recognition focused only on outcomes', pt: 'Reconhecimento focado apenas em resultados' },
    'c06-s2-li6': { en: 'Low psychological safety', pt: 'Baixa segurança psicológica' },
    'c06-s2-li7': { en: 'Unclear roles', pt: 'Papéis pouco claros' },
    'c06-s2-li8': { en: 'Transformation fatigue', pt: 'Fadiga de transformação' },
    'c06-s2-li9': { en: 'Limited coaching capability', pt: 'Capacidade de coaching limitada' },
    'c06-s2-p2': { en: 'The organization must address the immediate performance gap while protecting safety, quality, customer commitments, employee engagement, and financial discipline.', pt: 'A organização deve abordar a lacuna imediata de desempenho, protegendo ao mesmo tempo a segurança, a qualidade, os compromissos com os clientes, o envolvimento dos funcionários e a disciplina financeira.' },
    'c06-s3-li10': { en: 'KPI and data-quality review', pt: 'Revisão de KPI e qualidade de dados' },
