    'c06-s4-li5': { en: 'A significant share of the performance gap is caused by management-system weaknesses rather than isolated technical issues.', pt: 'Uma parte significativa da lacuna de desempenho é causada por deficiências do sistema de gestão e não por questões técnicas isoladas.' },
    'c06-s4-li6': { en: 'The organization lacks one reliable view of priorities, performance, and ownership.', pt: 'A organização carece de uma visão confiável de prioridades, desempenho e propriedade.' },
    'c06-s4-li7': { en: 'Local improvements will not sustain without governance, capability building, and leadership routines.', pt: 'As melhorias locais não serão sustentadas sem governação, capacitação e rotinas de liderança.' },
    'c06-s4-li8': { en: 'The transformation should be sequenced to stabilize, improve, and then scale.', pt: 'A transformação deve ser sequenciada para estabilizar, melhorar e depois escalar.' },
    'c06-s5-li10': { en: 'Recognize learning, collaboration, and results', pt: 'Reconheça o aprendizado, a colaboração e os resultados' },
    'c06-s5-li6': { en: 'Clarify purpose, roles, and decision boundaries', pt: 'Esclareça o propósito, as funções e os limites de decisão' },
    'c06-s5-li7': { en: 'Develop leaders as coaches', pt: 'Desenvolva líderes como treinadores' },
    'c06-s5-li8': { en: 'Create team-level transformation charters', pt: 'Crie cartas de transformação em nível de equipe' },
    'c06-s5-li9': { en: 'Use visible workload and priority management', pt: 'Use carga de trabalho visível e gerenciamento de prioridades' },
