    'c07-s7-th8': { en: 'Cadence', pt: 'Cadência' },
    'c07-s7-th9': { en: 'Purpose', pt: 'Objetivo' },
    'c07-s8-li11': { en: 'Critical control verification above 95%', pt: 'Verificação de controle crítico acima de 95%' },
    'c07-s8-li12': { en: 'High-risk action closure above 90%', pt: 'Fechamento de ações de alto risco acima de 90%' },
    'c07-s8-li13': { en: 'Near-miss reporting quality improvement', pt: 'Melhoria da qualidade dos relatórios de quase acidentes' },
    'c07-s8-li14': { en: 'Reduced repeat deviations', pt: 'Desvios de repetição reduzidos' },
    'c07-s8-li15': { en: 'Lower serious incident potential', pt: 'Menor potencial de incidentes graves' },
    'c07-s8-p3': { en: 'KPIs should include clear definitions, owners, data sources, targets, thresholds, and required actions when performance moves outside tolerance.', pt: 'Os KPIs devem incluir definições claras, proprietários, fontes de dados, metas, limites e ações necessárias quando o desempenho ultrapassar a tolerância.' },
    'c07-s9-td-13': { en: 'Transformation fatigue', pt: 'Fadiga de transformação' },
