    'c07-s9-td-21': { en: 'Employee resistance', pt: 'Resistência dos funcionários' },
    'c07-s9-td-22': { en: 'Involve users in design and provide role-based support', pt: 'Envolva os usuários no design e forneça suporte baseado em funções' },
    'c07-s9-td-23': { en: 'Operational disruption', pt: 'Interrupção operacional' },
    'c07-s9-td-24': { en: 'Pilot changes and use readiness gates before scaling', pt: 'Mudanças piloto e uso de portões de prontidão antes de escalar' },
    'c07-s9-th5': { en: 'Risk', pt: 'Risco' },
    'c07-s9-th6': { en: 'Mitigation', pt: 'Mitigação' },
    'c08-s1-p1': { en: 'Improvement initiatives occur, but they are episodic, consultant-dependent, and weakly connected to business priorities.', pt: 'Ocorrem iniciativas de melhoria, mas são episódicas, dependentes de consultores e fracamente ligadas às prioridades empresariais.' },
    'c08-s1-p2': { en: 'The recommended approach combines strategic prioritization, process redesign, governance, data discipline, leadership alignment, and change management. The objective is not only to improve short-term performance, but to create a management system capable of sustaining results.', pt: 'A abordagem recomendada combina priorização estratégica, redesenho de processos, governança, disciplina de dados, alinhamento de liderança e gestão de mudanças. O objetivo não é apenas melhorar o desempenho no curto prazo, mas criar um sistema de gestão capaz de sustentar resultados.' },
    'c08-s10-p1': { en: 'The transformation is expected to improve operational control, decision speed, accountability, workforce capability, customer outcomes, and financial performance. Final benefits would be validated jointly by operations and finance.', pt: 'Espera-se que a transformação melhore o controle operacional, a velocidade de decisão, a responsabilidade, a capacidade da força de trabalho, os resultados do cliente e o desempenho financeiro. Os benefícios finais seriam validados conjuntamente pelas operações e finanças.' },
    'c08-s11-p1': { en: 'Sustainable transformation is not a collection of isolated projects. It is a disciplined system that connects strategy, processes, people, governance, data, and value realization.', pt: 'A transformação sustentável não é um conjunto de projetos isolados. É um sistema disciplinado que conecta estratégia, processos, pessoas, governança, dados e realização de valor.' },
    'c08-s2-h3-1': { en: 'Current-State Signals', pt: 'Sinais do estado atual' },
    'c08-s2-li1': { en: 'Project selection by enthusiasm', pt: 'Seleção de projetos por entusiasmo' },
    'c08-s2-li2': { en: 'Limited benefits validation', pt: 'Validação de benefícios limitados' },
    'c08-s2-li3': { en: 'No standard CI roles', pt: 'Nenhuma função de CI padrão' },
    'c08-s2-li4': { en: 'Tools taught without business context', pt: 'Ferramentas ensinadas sem contexto de negócios' },
    'c08-s2-li5': { en: 'Results not embedded in routines', pt: 'Resultados não incorporados em rotinas' },
    'c08-s2-p1': { en: 'The organization must address the immediate performance gap while protecting safety, quality, customer commitments, employee engagement, and financial discipline.', pt: 'A organização deve abordar a lacuna imediata de desempenho, protegendo ao mesmo tempo a segurança, a qualidade, os compromissos com os clientes, o envolvimento dos funcionários e a disciplina financeira.' },
