    'c08-s4-li2': { en: 'The organization lacks one reliable view of priorities, performance, and ownership.', pt: 'A organização carece de uma visão confiável de prioridades, desempenho e propriedade.' },
    'c08-s4-li3': { en: 'Local improvements will not sustain without governance, capability building, and leadership routines.', pt: 'As melhorias locais não serão sustentadas sem governação, capacitação e rotinas de liderança.' },
    'c08-s4-li4': { en: 'The transformation should be sequenced to stabilize, improve, and then scale.', pt: 'A transformação deve ser sequenciada para estabilizar, melhorar e depois escalar.' },
