    'c09-s7-td1-1': { en: 'Executive Steering Committee', pt: 'Comitê de Direção Executivo' },
    'c09-s7-td1-2': { en: 'Monthly', pt: 'Mensalmente' },
    'c09-s7-td1-3': { en: 'Strategic decisions, value and risk', pt: 'Decisões estratégicas, valor e risco' },
    'c09-s7-td2-1': { en: 'Transformation Review', pt: 'Revisão de transformação' },
