    'c09-s7-th2': { en: 'Cadence', pt: 'Cadência' },
    'c09-s7-th3': { en: 'Purpose', pt: 'Objetivo' },
    'c09-s8-li1': { en: 'Planning time reduced', pt: 'Tempo de planejamento reduzido' },
    'c09-s8-li2': { en: 'Forecast accuracy improvement', pt: 'Melhoria da precisão da previsão' },
    'c09-s8-li3': { en: 'Lower administrative workload', pt: 'Menor carga de trabalho administrativo' },
    'c09-s8-li4': { en: 'User adoption above 75%', pt: 'Adoção do usuário acima de 75%' },
    'c09-s8-li5': { en: 'Verified financial or capacity value', pt: 'Valor financeiro ou de capacidade verificado' },
    'c09-s8-p1': { en: 'KPIs should include clear definitions, owners, data sources, targets, thresholds, and required actions when performance moves outside tolerance.', pt: 'Os KPIs devem incluir definições claras, proprietários, fontes de dados, metas, limites e ações necessárias quando o desempenho ultrapassar a tolerância.' },
    'c09-s9-td1-1': { en: 'Transformation fatigue', pt: 'Fadiga de transformação' },
