    'c10-s4-li4': { en: 'The transformation should be sequenced to stabilize, improve, and then scale.', pt: 'A transformação deve ser sequenciada para estabilizar, melhorar e depois escalar.' },
    'c10-s5-li1': { en: 'Segment inventory by value and variability', pt: 'Segmentar estoque por valor e variabilidade' },
