    'c10-s9-td4-2': { en: 'Assign process owners and audit post-implementation results', pt: 'Atribuir proprietários de processos e auditar resultados pós-implementação' },
    'c10-s9-td5-1': { en: 'Employee resistance', pt: 'Resistência dos funcionários' },
    'c10-s9-td5-2': { en: 'Involve users in design and provide role-based support', pt: 'Envolva os usuários no design e forneça suporte baseado em funções' },
    'c10-s9-td6-1': { en: 'Operational disruption', pt: 'Interrupção operacional' },
    'c10-s9-td6-2': { en: 'Pilot changes and use readiness gates before scaling', pt: 'Mudanças piloto e uso de portões de prontidão antes de escalar' },
    'c10-s9-th1': { en: 'Risk', pt: 'Risco' },
    'c10-s9-th2': { en: 'Mitigation', pt: 'Mitigação' },
    'c11-s1-p1': { en: 'Corporate processes suffer from long lead times, duplicated approvals, excessive meetings, and unclear ownership, reducing organizational speed.', pt: 'Os processos corporativos sofrem com longos prazos de entrega, aprovações duplicadas, reuniões excessivas e propriedade pouco clara, reduzindo a velocidade organizacional.' },
    'c11-s1-p2': { en: 'The recommended approach combines strategic prioritization, process redesign, governance, data discipline, leadership alignment, and change management. The objective is not only to improve short-term performance, but to create a management system capable of sustaining results.', pt: 'A abordagem recomendada combina priorização estratégica, redesenho de processos, governança, disciplina de dados, alinhamento de liderança e gestão de mudanças. O objetivo não é apenas melhorar o desempenho no curto prazo, mas criar um sistema de gestão capaz de sustentar resultados.' },
    'c11-s10-p1': { en: 'The transformation is expected to improve operational control, decision speed, accountability, workforce capability, customer outcomes, and financial performance. Final benefits would be validated jointly by operations and finance.', pt: 'Espera-se que a transformação melhore o controle operacional, a velocidade de decisão, a responsabilidade, a capacidade da força de trabalho, os resultados do cliente e o desempenho financeiro. Os benefícios finais seriam validados conjuntamente pelas operações e finanças.' },
    'c11-s11-p1': { en: 'Sustainable transformation is not a collection of isolated projects. It is a disciplined system that connects strategy, processes, people, governance, data, and value realization.', pt: 'A transformação sustentável não é um conjunto de projetos isolados. É um sistema disciplinado que conecta estratégia, processos, pessoas, governança, dados e realização de valor.' },
    'c11-s2-h3-1': { en: 'Current-State Signals', pt: 'Sinais do estado atual' },
    'c11-s2-li1': { en: 'Approval layers', pt: 'Camadas de aprovação' },
    'c11-s2-li2': { en: 'Duplicate data requests', pt: 'Solicitações de dados duplicadas' },
    'c11-s2-li3': { en: 'Meeting overload', pt: 'Sobrecarga de reuniões' },
    'c11-s2-li4': { en: 'Invisible queues', pt: 'Filas invisíveis' },
    'c11-s2-li5': { en: 'Functional handoffs', pt: 'Transferências funcionais' },
    'c11-s2-p1': { en: 'The organization must address the immediate performance gap while protecting safety, quality, customer commitments, employee engagement, and financial discipline.', pt: 'A organização deve abordar a lacuna imediata de desempenho, protegendo ao mesmo tempo a segurança, a qualidade, os compromissos com os clientes, o envolvimento dos funcionários e a disciplina financeira.' },
    'c11-s3-li1': { en: 'Executive and frontline stakeholder interviews', pt: 'Entrevistas com executivos e partes interessadas da linha de frente' },
    'c11-s3-li2': { en: 'Process and value-stream mapping', pt: 'Mapeamento de processos e fluxo de valor' },
    'c11-s3-li3': { en: 'KPI and data-quality review', pt: 'Revisão de KPI e qualidade de dados' },
    'c11-s3-li4': { en: 'Root-cause analysis', pt: 'Análise de causa raiz' },
    'c11-s3-li5': { en: 'Capability and governance assessment', pt: 'Avaliação de capacidade e governança' },
    'c11-s3-li6': { en: 'Financial value-leakage analysis', pt: 'Análise de vazamento de valor financeiro' },
    'c11-s3-li7': { en: 'Risk and change-readiness evaluation', pt: 'Avaliação de riscos e prontidão para mudanças' },
    'c11-s3-p1': { en: 'The assessment would combine:', pt: 'A avaliação combinaria:' },
    'c11-s4-li1': { en: 'A significant share of the performance gap is caused by management-system weaknesses rather than isolated technical issues.', pt: 'Uma parte significativa da lacuna de desempenho é causada por deficiências do sistema de gestão e não por questões técnicas isoladas.' },
    'c11-s4-li2': { en: 'The organization lacks one reliable view of priorities, performance, and ownership.', pt: 'A organização carece de uma visão confiável de prioridades, desempenho e propriedade.' },
    'c11-s4-li3': { en: 'Local improvements will not sustain without governance, capability building, and leadership routines.', pt: 'As melhorias locais não serão sustentadas sem governação, capacitação e rotinas de liderança.' },
    'c11-s4-li4': { en: 'The transformation should be sequenced to stabilize, improve, and then scale.', pt: 'A transformação deve ser sequenciada para estabilizar, melhorar e depois escalar.' },
    'c11-s5-li1': { en: 'Map high-friction employee journeys', pt: 'Mapeie jornadas de funcionários de alto atrito' },
    'c11-s5-li2': { en: 'Measure waiting and rework', pt: 'Meça a espera e o retrabalho' },
    'c11-s5-li3': { en: 'Simplify decision rights', pt: 'Simplifique os direitos de decisão' },
    'c11-s5-li4': { en: 'Create standard digital workflows', pt: 'Crie fluxos de trabalho digitais padrão' },
    'c11-s5-li5': { en: 'Redesign meetings around decisions', pt: 'Redesenhe reuniões em torno de decisões' },
    'c11-s6-h3-1': { en: 'Phase 1 — Diagnose and Stabilize | 0–30 Days', pt: 'Fase 1 — Diagnosticar e Estabilizar | 0–30 dias' },
    'c11-s6-h3-2': { en: 'Phase 2 — Redesign and Pilot | 31–90 Days', pt: 'Fase 2 — Redesenho e Piloto | 31–90 dias' },
    'c11-s6-h3-3': { en: 'Phase 3 — Scale and Embed | 3–12 Months', pt: 'Fase 3 — Dimensionar e Incorporar | 3–12 meses' },
    'c11-s6-li1': { en: 'Confirm baseline, scope, and value at stake', pt: 'Confirme a linha de base, o escopo e o valor em jogo' },
    'c11-s6-li10': { en: 'Validate operational and financial impact', pt: 'Valide o impacto operacional e financeiro' },
    'c11-s6-li11': { en: 'Scale proven practices', pt: 'Dimensione práticas comprovadas' },
    'c11-s6-li12': { en: 'Integrate standards into daily management', pt: 'Integre padrões na gestão diária' },
    'c11-s6-li13': { en: 'Link performance reviews to value realization', pt: 'Vincule as avaliações de desempenho à realização de valor' },
    'c11-s6-li14': { en: 'Develop internal transformation capability', pt: 'Desenvolver capacidade de transformação interna' },
    'c11-s6-li15': { en: 'Audit sustainability and adjust the operating model', pt: 'Auditar a sustentabilidade e ajustar o modelo operacional' },
    'c11-s6-li2': { en: 'Establish governance and decision rights', pt: 'Estabelecer governança e direitos de decisão' },
    'c11-s6-li3': { en: 'Contain critical operational and business risks', pt: 'Contenha riscos operacionais e de negócios críticos' },
    'c11-s6-li4': { en: 'Select priority workstreams', pt: 'Selecione fluxos de trabalho prioritários' },
    'c11-s6-li5': { en: 'Align leaders around a single transformation narrative', pt: 'Alinhe os líderes em torno de uma única narrativa de transformação' },
    'c11-s6-li6': { en: 'Redesign priority processes and management routines', pt: 'Redesenhar processos prioritários e rotinas de gestão' },
    'c11-s6-li7': { en: 'Pilot future-state solutions', pt: 'Soluções piloto para o estado futuro' },
    'c11-s6-li8': { en: 'Build dashboards and action-management standards', pt: 'Crie painéis e padrões de gerenciamento de ações' },
    'c11-s6-li9': { en: 'Train leaders and process owners', pt: 'Treine líderes e proprietários de processos' },
