    'c11-s7-th2': { en: 'Cadence', pt: 'Cadência' },
    'c11-s7-th3': { en: 'Purpose', pt: 'Objetivo' },
    'c11-s8-li1': { en: 'Administrative lead time reduced by 30%', pt: 'Lead time administrativo reduzido em 30%' },
    'c11-s8-li2': { en: 'Meeting hours reduced', pt: 'Horário de reuniões reduzido' },
    'c11-s8-li3': { en: 'Approval steps eliminated', pt: 'Etapas de aprovação eliminadas' },
    'c11-s8-li4': { en: 'Internal customer satisfaction improved', pt: 'Satisfação do cliente interno melhorou' },
    'c11-s8-li5': { en: 'Higher first-time-right rate', pt: 'Maior taxa de acerto na primeira vez' },
    'c11-s8-p1': { en: 'KPIs should include clear definitions, owners, data sources, targets, thresholds, and required actions when performance moves outside tolerance.', pt: 'Os KPIs devem incluir definições claras, proprietários, fontes de dados, metas, limites e ações necessárias quando o desempenho ultrapassar a tolerância.' },
    'c11-s9-td1-1': { en: 'Transformation fatigue', pt: 'Fadiga de transformação' },
    'c11-s9-td1-2': { en: 'Limit priorities and visibly stop low-value work', pt: 'Limitar as prioridades e interromper visivelmente o trabalho de baixo valor' },
    'c11-s9-td2-1': { en: 'Weak leadership alignment', pt: 'Fraco alinhamento de liderança' },
    'c11-s9-td2-2': { en: 'Use explicit decision rights and sponsor routines', pt: 'Use direitos de decisão explícitos e rotinas de patrocinador' },
