    'c11-s9-th2': { en: 'Mitigation', pt: 'Mitigação' },
    'c12-s1-p1': { en: 'A major operating-model change must be implemented while maintaining customer service, employee trust, and daily operational performance.', pt: 'Uma grande mudança no modelo operacional deve ser implementada, mantendo ao mesmo tempo o atendimento ao cliente, a confiança dos funcionários e o desempenho operacional diário.' },
    'c12-s1-p2': { en: 'The recommended approach combines strategic prioritization, process redesign, governance, data discipline, leadership alignment, and change management. The objective is not only to improve short-term performance, but to create a management system capable of sustaining results.', pt: 'A abordagem recomendada combina priorização estratégica, redesenho de processos, governança, disciplina de dados, alinhamento de liderança e gestão de mudanças. O objetivo não é apenas melhorar o desempenho no curto prazo, mas criar um sistema de gestão capaz de sustentar resultados.' },
    'c12-s10-p1': { en: 'The transformation is expected to improve operational control, decision speed, accountability, workforce capability, customer outcomes, and financial performance. Final benefits would be validated jointly by operations and finance.', pt: 'Espera-se que a transformação melhore o controle operacional, a velocidade de decisão, a responsabilidade, a capacidade da força de trabalho, os resultados do cliente e o desempenho financeiro. Os benefícios finais seriam validados conjuntamente pelas operações e finanças.' },
    'c12-s11-p1': { en: 'Sustainable transformation is not a collection of isolated projects. It is a disciplined system that connects strategy, processes, people, governance, data, and value realization.', pt: 'A transformação sustentável não é um conjunto de projetos isolados. É um sistema disciplinado que conecta estratégia, processos, pessoas, governança, dados e realização de valor.' },
    'c12-s2-h3-1': { en: 'Current-State Signals', pt: 'Sinais do estado atual' },
    'c12-s2-li1': { en: 'Change impacts not mapped', pt: 'Impactos de mudanças não mapeados' },
    'c12-s2-li2': { en: 'Communication is generic', pt: 'A comunicação é genérica' },
    'c12-s2-li3': { en: 'Leaders send inconsistent messages', pt: 'Líderes enviam mensagens inconsistentes' },
    'c12-s2-li4': { en: 'Training occurs too late', pt: 'O treinamento ocorre tarde demais' },
    'c12-s2-li5': { en: 'Operational readiness is assumed', pt: 'A prontidão operacional é assumida' },
    'c12-s2-p1': { en: 'The organization must address the immediate performance gap while protecting safety, quality, customer commitments, employee engagement, and financial discipline.', pt: 'A organização deve abordar a lacuna imediata de desempenho, protegendo ao mesmo tempo a segurança, a qualidade, os compromissos com os clientes, o envolvimento dos funcionários e a disciplina financeira.' },
