    'c13-s8-li1': { en: 'Portfolio strategic alignment', pt: 'Alinhamento estratégico do portfólio' },
    'c13-s8-li2': { en: 'NPV and payback quality', pt: 'VPL e qualidade de retorno' },
    'c13-s8-li3': { en: 'Project delivery reliability', pt: 'Confiabilidade na entrega do projeto' },
    'c13-s8-li4': { en: 'Benefits realization above 85%', pt: 'Realização de benefícios acima de 85%' },
    'c13-s8-li5': { en: 'Reduced emergency CAPEX', pt: 'CAPEX emergencial reduzido' },
    'c13-s8-p1': { en: 'KPIs should include clear definitions, owners, data sources, targets, thresholds, and required actions when performance moves outside tolerance.', pt: 'Os KPIs devem incluir definições claras, proprietários, fontes de dados, metas, limites e ações necessárias quando o desempenho ultrapassar a tolerância.' },
    'c13-s9-td1-1': { en: 'Transformation fatigue', pt: 'Fadiga de transformação' },
    'c13-s9-td1-2': { en: 'Limit priorities and visibly stop low-value work', pt: 'Limitar as prioridades e interromper visivelmente o trabalho de baixo valor' },
    'c13-s9-td2-1': { en: 'Weak leadership alignment', pt: 'Fraco alinhamento de liderança' },
    'c13-s9-td2-2': { en: 'Use explicit decision rights and sponsor routines', pt: 'Use direitos de decisão explícitos e rotinas de patrocinador' },
    'c13-s9-td3-1': { en: 'Poor data quality', pt: 'Má qualidade de dados' },
