    'c13-s9-th1': { en: 'Risk', pt: 'Risco' },
    'c13-s9-th2': { en: 'Mitigation', pt: 'Mitigação' },
    'c14-s1-p1': { en: 'A company has launched many strategic initiatives but lacks enterprise visibility, dependency management, and disciplined value delivery.', pt: 'Uma empresa lançou muitas iniciativas estratégicas, mas carece de visibilidade empresarial, gestão de dependências e entrega disciplinada de valor.' },
    'c14-s1-p2': { en: 'The recommended approach combines strategic prioritization, process redesign, governance, data discipline, leadership alignment, and change management. The objective is not only to improve short-term performance, but to create a management system capable of sustaining results.', pt: 'A abordagem recomendada combina priorização estratégica, redesenho de processos, governança, disciplina de dados, alinhamento de liderança e gestão de mudanças. O objetivo não é apenas melhorar o desempenho no curto prazo, mas criar um sistema de gestão capaz de sustentar resultados.' },
    'c14-s10-p1': { en: 'The transformation is expected to improve operational control, decision speed, accountability, workforce capability, customer outcomes, and financial performance. Final benefits would be validated jointly by operations and finance.', pt: 'Espera-se que a transformação melhore o controle operacional, a velocidade de decisão, a responsabilidade, a capacidade da força de trabalho, os resultados do cliente e o desempenho financeiro. Os benefícios finais seriam validados conjuntamente pelas operações e finanças.' },
    'c14-s11-p1': { en: 'Sustainable transformation is not a collection of isolated projects. It is a disciplined system that connects strategy, processes, people, governance, data, and value realization.', pt: 'A transformação sustentável não é um conjunto de projetos isolados. É um sistema disciplinado que conecta estratégia, processos, pessoas, governança, dados e realização de valor.' },
    'c14-s2-h3-1': { en: 'Current-State Signals', pt: 'Sinais do estado atual' },
    'c14-s2-li1': { en: 'Too many initiatives', pt: 'Muitas iniciativas' },
    'c14-s2-li2': { en: 'No single source of truth', pt: 'Nenhuma fonte única de verdade' },
