    'job7-title': { en: 'Trainee', pt: 'Estagiário' },
    'job8-b1': { en: 'Synthesized catalysts and performed analysis using TPD, X-RAY, ASAP 2010 and catalytic tests in chromatograph.', pt: 'Sintetizei catalisadores e realizei análises utilizando TPD, X-RAY, ASAP 2010 e testes catalíticos em cromatógrafo.' },
    'job8-b2': { en: 'Part of a Petrobras project focused on finding larger pores for zeolites used in crude-oil catalysis.', pt: 'Parte de um projeto da Petrobras focado em encontrar poros maiores para zeólitas usadas na catálise de petróleo bruto.' },
